 8	interface CopilotAdapterOptions {
 9	  env?: Record<string, string | undefined>;
10	}
11	
12	export function createCopilotAdapter(
13	  options: CopilotAdapterOptions = {}
14	): ProviderAdapter {
15	  return {
16	    provider: "copilot",
17	    async execute<TResult>(
18	      request: ProviderExecutionRequest<TResult>
19	    ) {
20	      if (request.resumeSessionId) {
21	        return {
22	          provider: "copilot" as const,
23	          stdout: "",
24	          stderr: "Copilot continuation is not supported for retained implementor sessions in v1.",
25	          exitCode: 1,
26	          errorCode: "CONTINUATION_HANDLE_INVALID",
27	        };
28	      }
29	
30	      const execution = await runProviderCommand({
31	        provider: "copilot",
32	        executable: "copilot",
33	        args: ["-p", request.prompt, "-s", "--model", request.model],
34	        cwd: request.cwd,
35	        env: options.env,
36	        timeoutMs: request.timeoutMs,
37	      });
38	
39	      if (execution.exitCode !== 0) {
40	        return execution;
41	      }
42	
43	      const parsed = parseProviderPayload({
44	        stdout: execution.stdout,
45	        resultSchema: request.resultSchema,
46	      });
47	
48	      return {
49	        ...execution,
50	        sessionId: parsed.sessionId,
51	        parsedResult: parsed.parsedResult,
52	        parseError: parsed.parseError,
53	      };
54	    },
55	  };
56	}

