 6	export const RUN_CONFIG_FILE_NAME = "impl-run.config.json";
 7	
 8	export const reasoningEffortSchema = z.enum(["low", "medium", "high", "xhigh"]);
 9	export const primaryHarnessSchema = z.literal("claude-code");
10	export const secondaryHarnessSchema = z.enum(["codex", "copilot", "none"]);
11	
12	export const roleAssignmentSchema = z.object({
13	  secondary_harness: secondaryHarnessSchema,
14	  model: z.string().min(1),
15	  reasoning_effort: reasoningEffortSchema,
16	});
17	
18	export const epicVerifierAssignmentSchema = roleAssignmentSchema.extend({
19	  label: z.string().min(1),
20	});
21	
22	export const implRunConfigSchema = z
23	  .object({
24	    version: z.literal(1),
25	    primary_harness: primaryHarnessSchema,
26	    story_implementor: roleAssignmentSchema,
27	    quick_fixer: roleAssignmentSchema,
28	    story_verifier_1: roleAssignmentSchema,
29	    story_verifier_2: roleAssignmentSchema,
30	    self_review: z.object({
31	      passes: z.number().int().min(1).max(5),
32	    }),
33	    epic_verifiers: z.array(epicVerifierAssignmentSchema).min(1),
34	    epic_synthesizer: roleAssignmentSchema,
35	  })
36	  .superRefine((value, ctx) => {
37	    if (value.story_implementor.secondary_harness === "copilot") {
38	      ctx.addIssue({
39	        code: z.ZodIssueCode.custom,
40	        message:
41	          "story_implementor.secondary_harness cannot be copilot in v1",
42	        path: ["story_implementor", "secondary_harness"],
43	      });
44	    }
45	
46	    const seenLabels = new Set<string>();
47	    for (const [index, verifier] of value.epic_verifiers.entries()) {
48	      if (seenLabels.has(verifier.label)) {
49	        ctx.addIssue({
50	          code: z.ZodIssueCode.custom,
51	          message: "Duplicate epic verifier label",
52	          path: ["epic_verifiers", index, "label"],
53	        });
54	      }
55	      seenLabels.add(verifier.label);
56	    }
57	  });
58	
59	export type ReasoningEffort = z.infer<typeof reasoningEffortSchema>;
60	export type PrimaryHarness = z.infer<typeof primaryHarnessSchema>;
61	export type SecondaryHarness = z.infer<typeof secondaryHarnessSchema>;
62	export type RoleAssignment = z.infer<typeof roleAssignmentSchema>;
63	export type EpicVerifierAssignment = z.infer<typeof epicVerifierAssignmentSchema>;
64	export type ImplRunConfig = z.infer<typeof implRunConfigSchema>;
65	
66	export function resolveRunConfigPath(
67	  specPackRoot: string,
68	  configPath?: string
69	): string {
70	  if (!configPath) {
71	    return resolve(specPackRoot, RUN_CONFIG_FILE_NAME);
72	  }
73	
74	  return resolve(specPackRoot, configPath);
75	}
76	
77	export async function loadRunConfig(input: {
78	  specPackRoot: string;
79	  configPath?: string;
80	}): Promise<ImplRunConfig> {
81	  const resolvedPath = resolveRunConfigPath(input.specPackRoot, input.configPath);
82	  const { config } = await loadConfig({
83	    cwd: resolve(input.specPackRoot),
84	    configFile: relative(resolve(input.specPackRoot), resolvedPath),
85	    configFileRequired: true,
86	    rcFile: false,
87	    globalRc: false,
88	    packageJson: false,
89	    dotenv: false,
90	    extend: false,
91	  });
92	
93	  return implRunConfigSchema.parse(config);
94	}

