302	  try {
303	    return {
304	      assetId: basename(path),
305	      content: await readTextFile(path),
306	    };
307	  } catch (error) {
308	    throw new PromptInsertError(
309	      `Public prompt insert could not be read: ${path}${
310	        error instanceof Error ? ` (${error.message})` : ""
311	      }`
312	    );
313	  }
