332	export async function assemblePrompt(
333	  input: PromptAssemblyInput
334	): Promise<PromptAssemblyResult> {
335	  const assets = getEmbeddedPromptAssets();
336	  const basePromptId = basePromptIdForRole(input.role);
337	  const snippetIds = snippetIdsForInput(input);
338	  const values = runtimeValues(input);
339	  const publicInsert =
340	    input.role === "story_implementor"
341	      ? await loadPublicInsert(input.implementationPromptInsertPath)
342	      : input.role === "story_verifier"
343	        ? await loadPublicInsert(input.verifierPromptInsertPath)
344	        : {};
345	
346	  const sections = [
347	    interpolateTemplate(assets.base[basePromptId], values),
348	    ...snippetIds.map((snippetId) =>
349	      interpolateTemplate(assets.snippets[snippetId], values)
350	    ),
351	    selfReviewSection(input),
352	    followupSection(input),
353	    publicInsert.content ? publicInsert.content.trimEnd() : "",
354	  ].filter((section) => section.length > 0);
355	
356	  return {
357	    prompt: `${sections.join("\n\n")}\n`,
358	    basePromptId,
359	    snippetIds,
360	    publicInsertIds: publicInsert.assetId ? [publicInsert.assetId] : [],
361	  };
362	}

