277	async function executePrompt(input: {
278	  provider: ProviderName;
279	  specPackRoot: string;
280	  model: string;
281	  reasoningEffort: string;
282	  prompt: string;
283	  resumeSessionId?: string;
284	  env?: Record<string, string | undefined>;
285	}): Promise<PromptExecutionSuccess | PromptExecutionFailure> {
286	  const adapter = createProviderAdapter(input.provider, {
287	    env: input.env,
288	  });
289	  const execution = await adapter.execute({
290	    prompt: input.prompt,
291	    cwd: input.specPackRoot,
292	    model: input.model,
293	    reasoningEffort: input.reasoningEffort,
294	    resumeSessionId: input.resumeSessionId,
295	    timeoutMs: 30_000,
296	    resultSchema: providerPayloadSchema,
297	  });
298	
299	  if (execution.exitCode !== 0) {
300	    return {
301	      outcome: "blocked" as const,
302	      errors: [
303	        executionFailureError({
304	          provider: input.provider,
305	          stderr: execution.stderr,
306	          errorCode: execution.errorCode,
307	        }),
308	      ],
309	    };
310	  }
311	
312	  if (execution.parseError || !execution.parsedResult) {
313	    return {
314	      outcome: "blocked" as const,
315	      errors: [
316	        blockedError(
317	          "PROVIDER_OUTPUT_INVALID",
318	          `Provider output was invalid for ${input.provider}.`,
319	          execution.parseError
320	        ),
321	      ],
322	    };
323	  }
324	
325	  const sessionId = execution.sessionId ?? input.resumeSessionId;
326	  if (!sessionId) {
327	    return {
328	      outcome: "blocked" as const,
329	      errors: [
330	        blockedError(
331	          "CONTINUATION_HANDLE_INVALID",
332	          `Provider ${input.provider} did not return a session id for a retained implementor workflow.`
333	        ),
334	      ],
335	    };
336	  }
337	
338	  return {
339	    outcome: execution.parsedResult.outcome,
340	    sessionId,
341	    payload: execution.parsedResult,
342	  };
343	}
