345	async function resolveContinuationOwner(input: {
346	  specPackRoot: string;
347	  provider: ProviderName;
348	  sessionId: string;
349	}): Promise<string | null> {
350	  const artifactsRoot = join(resolve(input.specPackRoot), "artifacts");
351	  if (!(await pathExists(artifactsRoot))) {
352	    return null;
353	  }
354	
355	  const groups = await readdir(artifactsRoot, { withFileTypes: true });
356	  for (const group of groups) {
357	    if (!group.isDirectory()) {
358	      continue;
359	    }
360	
361	    const groupPath = join(artifactsRoot, group.name);
362	    const entries = await readdir(groupPath, { withFileTypes: true });
363	    for (const entry of entries) {
364	      if (!entry.isFile() || !entry.name.endsWith(".json")) {
365	        continue;
366	      }
367	
368	      try {
369	        const content = JSON.parse(
370	          await readTextFile(join(groupPath, entry.name))
371	        ) as {
372	          result?: {
373	            continuation?: {
374	              provider?: string;
375	              sessionId?: string;
376	              storyId?: string;
377	            };
378	          };
379	        };
380	        const continuation = content.result?.continuation;
381	        if (
382	          continuation?.provider === input.provider &&
383	          continuation?.sessionId === input.sessionId
384	        ) {
385	          return continuation.storyId ?? group.name;
386	        }
387	      } catch {}
388	    }
389	  }
390	
391	  return null;
392	}
