394	export async function validateContinuationHandle(input: {
395	  specPackRoot: string;
396	  storyId: string;
397	  provider: string;
398	  sessionId: string;
399	}): Promise<CliError | null> {
400	  const provider = providerIdSchema.safeParse(input.provider);
401	  if (!provider.success) {
402	    return blockedError(
403	      "CONTINUATION_HANDLE_INVALID",
404	      `Provider '${input.provider}' is not a valid continuation provider.`
405	    );
406	  }
407	
408	  if (provider.data === "copilot") {
409	    return blockedError(
410	      "CONTINUATION_HANDLE_INVALID",
411	      "Provider 'copilot' cannot be used for retained story_implementor continuation sessions."
412	    );
413	  }
414	
415	  const owner = await resolveContinuationOwner({
416	    specPackRoot: input.specPackRoot,
417	    provider: provider.data,
418	    sessionId: input.sessionId,
419	  });
420	  if (owner === input.storyId) {
421	    return null;
422	  }
423	
424	  if (owner) {
425	    return blockedError(
426	      "CONTINUATION_HANDLE_INVALID",
427	      `Continuation handle ${input.sessionId} belongs to '${owner}', not '${input.storyId}'.`
428	    );
429	  }
430	
431	  return blockedError(
432	    "CONTINUATION_HANDLE_INVALID",
433	    `Continuation handle ${input.sessionId} was not found for story '${input.storyId}'.`
434	  );
435	}
