311	export async function runStoryVerify(input: {
312	  specPackRoot: string;
313	  storyId: string;
314	  configPath?: string;
315	  env?: Record<string, string | undefined>;
316	}): Promise<StoryVerifyWorkflowResult> {
317	  const context = await prepareStoryVerifyContext(input);
318	  if ("errors" in context) {
319	    return {
320	      outcome: "block",
321	      errors: context.errors,
322	      warnings: [],
323	    };
324	  }
325	
326	  try {
327	    const executions = await Promise.all(
328	      context.verifiers.map(async (verifier) => {
329	        const prompt = await assemblePrompt({
330	          role: "story_verifier",
331	          verifierLabel: verifier.label,
332	          storyId: context.story.id,
333	          storyTitle: context.story.title,
334	          storyPath: context.story.path,
335	          epicPath: context.paths.epicPath,
336	          techDesignPath: context.paths.techDesignPath,
337	          techDesignCompanionPaths: context.paths.techDesignCompanionPaths,
338	          testPlanPath: context.paths.testPlanPath,
339	          gateCommands: context.gateCommands,
340	          verifierPromptInsertPath: context.verifierPromptInsertPath,
341	        });
342	        const execution = await executeVerifier({
343	          provider: verifier.provider,
344	          specPackRoot: context.specPackRoot,
345	          model: verifier.model,
346	          reasoningEffort: verifier.reasoningEffort,
347	          prompt: prompt.prompt,
348	          env: input.env,
349	        });
350	
351	        if ("errors" in execution) {
352	          return execution;
353	        }
354	
355	        return {
356	          result: buildVerifierResult({
357	            verifier,
358	            story: context.story,
359	            payload: execution.payload,
360	          }),
361	        };
362	      })
363	    );
364	
365	    const errors = executions.flatMap((execution) =>
366	      "errors" in execution ? execution.errors : []
367	    );
368	    const verifierResults = executions.flatMap((execution) =>
369	      "result" in execution ? [execution.result] : []
370	    );
371	    if (errors.length > 0) {
372	      return {
373	        outcome: "block",
374	        result:
375	          verifierResults.length > 0
376	            ? buildVerifierBatchResult({
377	                outcome: "block",
378	                story: context.story,
379	                verifierResults,
380	              })
381	            : undefined,
382	        errors,
383	        warnings: [],
384	      };
385	    }
386	
387	    const outcome = aggregateVerifierBatchOutcome(verifierResults);
388	
389	    return {
390	      outcome,
391	      result: buildVerifierBatchResult({
392	        outcome,
393	        story: context.story,
394	        verifierResults,
395	      }),
396	      errors: [],
397	      warnings: [],
398	    };
399	  } catch (error) {
400	    const failure = promptInsertFailure(error);
401	    if (failure) {
402	      return failure;
403	    }
404	
405	    throw error;
406	  }
407	}

