387	function statusForOutcome(outcome: string): CliStatus {
388	  switch (outcome) {
389	    case "ready":
390	    case "ready-for-verification":
391	    case "needs-followup-fix":
392	    case "pass":
393	    case "revise":
394	    case "cleaned":
395	    case "needs-more-cleanup":
396	    case "ready-for-closeout":
397	    case "needs-fixes":
398	    case "needs-more-routing":
399	    case "needs-more-verification":
400	      return "ok";
401	    case "block":
402	      return "blocked";
403	    case "needs-user-decision":
404	    case "needs-human-ruling":
405	      return "needs-user-decision";
406	    case "blocked":
407	      return "blocked";
408	    default:
409	      return "error";
410	  }
411	}
412	
413	const zeroExitOutcomes = new Set([
414	  "ready",
415	  "ready-for-verification",
416	  "pass",
417	  "cleaned",
418	  "ready-for-closeout",
419	]);
420	
421	export function exitCodeForStatus(status: CliStatus, outcome?: string): number {
422	  switch (status) {
423	    case "ok":
424	      return outcome && !zeroExitOutcomes.has(outcome) ? 2 : 0;
425	    case "needs-user-decision":
426	      return 2;
427	    case "blocked":
428	      return 3;
429	    case "error":
430	    default:
431	      return 1;
432	  }
433	}
