310	export async function writeFakeProviderExecutable(params: {
311	  binDir: string;
312	  provider: "claude" | "codex" | "copilot";
313	  responses?: FakeProviderResponse[];
314	  version?: string;
315	  authStatus?: "authenticated" | "missing";
316	  authStdout?: string;
317	  authStderr?: string;
318	}) {
319	  const prefix = params.provider.toUpperCase().replace(/-/g, "_");
320	  const scriptPath = join(params.binDir, params.provider);
321	  const logPath = join(params.binDir, `${params.provider}-invocations.jsonl`);
322	  const responsesPath = join(params.binDir, `${params.provider}-responses.json`);
323	  const cursorPath = join(params.binDir, `${params.provider}-cursor.txt`);
324	
325	  await writeTextFile(
326	    responsesPath,
327	    `${JSON.stringify(params.responses ?? [], null, 2)}\n`
328	  );
329	  await writeTextFile(cursorPath, "0\n");
330	  await writeTextFile(
331	    scriptPath,
332	    [
333	      "#!/usr/bin/env bun",
334	      "import { appendFileSync, existsSync, readFileSync, writeFileSync } from \"node:fs\";",
335	      "import { basename } from \"node:path\";",
336	      "",
337	      "const provider = basename(process.argv[1]);",
338	      "const prefix = provider.toUpperCase().replace(/-/g, \"_\");",
339	      "const envKey = (name) => `${prefix}_${name}`;",
340	      "const args = process.argv.slice(2);",
341	      "const logPath = process.env[envKey(\"LOG_PATH\")];",
342	      "",
343	      "if (logPath) {",
344	      "  appendFileSync(logPath, `${JSON.stringify({ provider, cwd: process.cwd(), args })}\\n`);",
345	      "}",
346	      "",
347	      "if (args.length === 1 && args[0] === \"--version\") {",
348	      "  process.stdout.write(process.env[envKey(\"VERSION\")] ?? `${provider} 1.0.0`);",
349	      "  process.exit(Number(process.env[envKey(\"VERSION_EXIT_CODE\")] ?? 0));",
350	      "}",
351	      "",
352	      "if (args[0] === \"auth\" && args[1] === \"status\") {",
353	      "  const authStatus = process.env[envKey(\"AUTH_STATUS\")] ?? \"authenticated\";",
354	      "  if (authStatus === \"authenticated\") {",
355	      "    process.stdout.write(process.env[envKey(\"AUTH_STDOUT\")] ?? \"authenticated\");",
356	      "    process.exit(0);",
357	      "  }",
358	      "  process.stderr.write(process.env[envKey(\"AUTH_STDERR\")] ?? \"missing\");",
359	      "  process.exit(1);",
360	      "}",
361	      "",
362	      "const responsesPath = process.env[envKey(\"RESPONSES_PATH\")];",
363	      "const cursorPath = process.env[envKey(\"CURSOR_PATH\")];",
364	      "if (!responsesPath || !cursorPath) {",
365	      "  process.stderr.write(\"Missing fake provider response configuration\");",
366	      "  process.exit(1);",
367	      "}",
368	      "",
369	      "const responses = JSON.parse(readFileSync(responsesPath, \"utf8\"));",
370	      "const rawCursor = existsSync(cursorPath) ? readFileSync(cursorPath, \"utf8\").trim() : \"0\";",
371	      "const cursor = Number(rawCursor || \"0\");",
372	      "const response = responses[cursor] ?? responses[responses.length - 1] ?? {",
373	      "  stderr: \"No fake provider response configured\",",
374	      "  exitCode: 1,",
375	      "};",
376	      "writeFileSync(cursorPath, `${cursor + 1}`);",
377	      "if (response.stderr) {",
378	      "  process.stderr.write(response.stderr);",
379	      "}",
380	      "if (response.stdout) {",
381	      "  process.stdout.write(response.stdout);",
382	      "}",
383	      "process.exit(Number(response.exitCode ?? 0));",
384	      "",
385	    ].join("\n")
386	  );
387	  await chmod(scriptPath, 0o755);
388	
389	  return {
390	    logPath,
391	    env: {
392	      [`${prefix}_LOG_PATH`]: logPath,
393	      [`${prefix}_RESPONSES_PATH`]: responsesPath,
394	      [`${prefix}_CURSOR_PATH`]: cursorPath,
395	      [`${prefix}_VERSION`]: params.version ?? `${params.provider} 1.0.0`,
396	      [`${prefix}_AUTH_STATUS`]: params.authStatus ?? "authenticated",
397	      ...(params.authStdout
398	        ? {
399	            [`${prefix}_AUTH_STDOUT`]: params.authStdout,
400	          }
401	        : {}),
402	      ...(params.authStderr
403	        ? {
404	            [`${prefix}_AUTH_STDERR`]: params.authStderr,
405	          }
406	        : {}),
407	    } satisfies Record<string, string>,
408	  };
409	}
