411	export async function readJsonLines<T>(path: string): Promise<T[]> {
412	  const content = await Bun.file(path).text();
413	  return content
414	    .split("\n")
415	    .map((line) => line.trim())
416	    .filter(Boolean)
417	    .map((line) => JSON.parse(line) as T);
418	}
