105	export async function runQuickFix(input: {
106	  specPackRoot: string;
107	  request: string;
108	  workingDirectory?: string;
109	  configPath?: string;
110	  env?: Record<string, string | undefined>;
111	}): Promise<QuickFixWorkflowResult> {
112	  const config = await loadRunConfig({
113	    specPackRoot: input.specPackRoot,
114	    configPath: input.configPath,
115	  });
116	  const provider = providerForHarness(config.quick_fixer.secondary_harness);
117	  const workingDirectoryResolution = await resolveWorkingDirectory({
118	    specPackRoot: input.specPackRoot,
119	    workingDirectory: input.workingDirectory,
120	  });
121	  if (workingDirectoryResolution.errors) {
122	    return {
123	      outcome: "blocked",
124	      errors: workingDirectoryResolution.errors,
125	      warnings: [],
126	    };
127	  }
128	  const workingDirectory = workingDirectoryResolution.workingDirectory;
129	  if (!workingDirectory) {
130	    return {
131	      outcome: "blocked",
132	      errors: [
133	        blockedError(
134	          "INVALID_WORKING_DIRECTORY",
135	          "Quick-fix working directory could not be resolved."
136	        ),
137	      ],
138	      warnings: [],
139	    };
140	  }
141	  const adapter = createProviderAdapter(provider, {
142	    env: input.env,
143	  });
144	  const execution = await adapter.execute({
145	    prompt: input.request,
146	    cwd: workingDirectory,
147	    model: config.quick_fixer.model,
148	    reasoningEffort: config.quick_fixer.reasoning_effort,
149	    timeoutMs: 30_000,
150	  });
151	
152	  if (execution.exitCode !== 0) {
153	    return {
154	      outcome: "blocked",
155	      errors: [
156	        executionFailureError({
157	          provider,
158	          stderr: execution.stderr,
159	          errorCode: execution.errorCode,
160	        }),
161	      ],
162	      warnings: [],
163	    };
164	  }
165	
166	  const rawProviderOutput = execution.stdout;
167	  if (rawProviderOutput.trim().length === 0) {
168	    return {
169	      outcome: "needs-more-routing",
170	      result: {
171	        provider,
172	        model: config.quick_fixer.model,
173	        rawProviderOutput,
174	      },
175	      errors: [],
176	      warnings: [
177	        "Quick-fix provider returned no stdout; inspect the run and choose the next routing step explicitly.",
178	      ],
179	    };
180	  }
181	
182	  return {
183	    outcome: "ready-for-verification",
184	    result: {
185	      provider,
186	      model: config.quick_fixer.model,
187	      rawProviderOutput,
188	    },
189	    errors: [],
190	    warnings: [],
191	  };
192	}

